import{_ as a,o as t,c as l,ai as n}from"./chunks/framework.ampVZV4B.js";const h=JSON.parse('{"title":"01 Agent 是什么：LLM + Tools + 循环","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-2-agent/01-agent-overview.md","filePath":"ai/stage-2-agent/01-agent-overview.md"}'),o={name:"ai/stage-2-agent/01-agent-overview.md"};function i(r,e,s,g,_,d){return t(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="_01-agent-是什么-llm-tools-循环" tabindex="-1">01 Agent 是什么：LLM + Tools + 循环 <a class="header-anchor" href="#_01-agent-是什么-llm-tools-循环" aria-label="Permalink to “01 Agent 是什么：LLM + Tools + 循环”">​</a></h1><blockquote><p>目标：把 Agent 想清楚，避免“上来就学框架，越学越乱”。</p></blockquote><h2 id="_1-一句话理解-agent" tabindex="-1">1）一句话理解 Agent <a class="header-anchor" href="#_1-一句话理解-agent" aria-label="Permalink to “1）一句话理解 Agent”">​</a></h2><p><strong>Agent = LLM（理解/规划） + Tools（执行动作） + Loop（反复执行直到完成）</strong>。</p><p>LLM 负责“想”和“说”，Tools 负责“做”：</p><ul><li>查数据（HTTP/DB）</li><li>读写文件（Markdown/JSON）</li><li>调用你自己的业务接口</li></ul><h2 id="_2-agent-的最小闭环-你必须做出来" tabindex="-1">2）Agent 的最小闭环（你必须做出来） <a class="header-anchor" href="#_2-agent-的最小闭环-你必须做出来" aria-label="Permalink to “2）Agent 的最小闭环（你必须做出来）”">​</a></h2><ol><li>用户输入任务（例如：给我生成“Redis 高频题”）</li><li>LLM 决定要用什么工具（例如：读取某篇笔记）</li><li>工具执行并返回结果（读到文本）</li><li>LLM 基于结果生成输出（题目/答案）</li><li>再调用工具写回文件（生成新 Markdown）</li></ol><h2 id="_3-你现在最适合做的-agent-场景" tabindex="-1">3）你现在最适合做的 Agent 场景 <a class="header-anchor" href="#_3-你现在最适合做的-agent-场景" aria-label="Permalink to “3）你现在最适合做的 Agent 场景”">​</a></h2><p>围绕你这个 VitePress 知识库：</p><ul><li>输入：模块名（Java/数据库/Redis/框架/物联网）</li><li>输出：一篇新页面（题库/学习计划/口语化回答模板）</li></ul><blockquote><p>这类 Agent 最容易落地，也最适合你“求职面试”主线。</p></blockquote>',12)])])}const p=a(o,[["render",i]]);export{h as __pageData,p as default};
